example.programlisting:
@cs Name = "README.txt"           ## Sensible à la casse : correspond uniquement à "README.txt"
@ci Name = "readme.txt"           ## Insensible à la casse : correspond à "README.txt", "readme.txt", "ReadMe.TXT", etc.
@casesensitive Extension = "TXT"  ## Sensible à la casse : correspond uniquement aux fichiers avec l'extension ".TXT"
@caseinsensitive Content contains "error"  ## Insensible à la casse : correspond à "Error", "ERROR", "error", etc.

@optimize Size > 10MB and Extension = "log"     ## Active l'optimisation (par défaut)
@noopt Name matches "complex[0-9]+pattern"    ## Désactive l'optimisation pour le débogage
@nooptimize Content contains "special-case"   ## Désactive l'optimisation

@name="Gros fichiers images" Size > 10MB and Extension = "png"
@name=PetitsFichiersTexte Size < 1KB and Extension = "txt"
@name="Modifié aujourd'hui" Date >= today()
@name="Filtre de test" @cs Name like "test_*.cpp"
